import * as React from "react";
import PropTypes from "prop-types";
import { Link } from "gatsby";

// 讀取 JSON 數據
import data from "../data/blog.json";

/**
 * Navigation component
 *
 * Loads navigation items from a local JSON file instead of Ghost API.
 * Differentiates between absolute (external) and relative (internal) links.
 */
const Navigation = ({ navClass }) => {
    const navItems = data.allGhostSettings.edges[0].node.navigation;

    return (
        <>
            {navItems.map((navItem, i) => {
                if (navItem.url.match(/^\s?http(s?)/gi)) {
                    return (
                        <a
                            className={navClass}
                            href={navItem.url}
                            key={i}
                            target="_blank"
                            rel="noopener noreferrer"
                        >
                            {navItem.label}
                        </a>
                    );
                } else {
                    return (
                        <Link className={navClass} to={navItem.url} key={i}>
                            {navItem.label}
                        </Link>
                    );
                }
            })}
        </>
    );
};

Navigation.defaultProps = {
    navClass: `site-nav-item`,
};

Navigation.propTypes = {
    navClass: PropTypes.string,
};

export default Navigation;
