import * as React from "react";
import PropTypes from "prop-types";
import { Helmet } from "react-helmet";
import { Link } from "gatsby";
import { Navigation } from ".";
// import config from "../utils/siteConfig";

// 讀取 JSON 數據
import data from "../data/blog.json";

// Styles
import "../styles/app.css";

/**
 * Main layout component
 *
 * The Layout component wraps around each page and template.
 * It also provides the header, footer as well as the main
 * styles, and meta data for each page.
 *
 */
const DefaultLayout = ({ children, bodyClass, isHome }) => {
    const site = data.allGhostSettings.edges[0].node;
    // const siteIcon = data.file.childImageSharp.gatsbyImageData.images.fallback.src;
    
    // const githubUrl = site.github ? `https://github.com/${site.github.replace(/^@/, ``)}` : null;
    // const linkedinUrl = site.linkedin ? `https://www.linkedin.com/${site.linkedin.replace(/^\//, ``)}` : null;

    const githubUrl = site.github;
    const linkedinUrl = site.linkedin;
    const gmailUrl = site.gmail;

    return (
        <>
            <Helmet>
                <html lang={site.lang} />
                <style type="text/css">{`${site.codeinjection_styles || ""}`}</style>
                <body className={bodyClass} />
            </Helmet>

            <div className="viewport">
                <div className="viewport-top">
                    {/* The main header section on top of the screen */}
                    <header
                        className="site-head"
                        style={{
                            ...(site.cover_image && {
                                backgroundImage: `url(${site.cover_image})`,
                            }),
                        }}
                    >
                        <div className="container">
                            <div className="site-mast">
                                <div className="site-mast-left">
                                </div>
                                <div className="site-mast-right">
                                    {githubUrl && (
                                        <a href={githubUrl} className="site-nav-item-icon" target="_blank" rel="noopener noreferrer">
                                            <img
                                                className="site-nav-icon-github"
                                                src="/images/icons/github.png"
                                                alt="github"
                                            />
                                        </a>
                                    )}
                                    {linkedinUrl && (
                                        <a href={linkedinUrl} className="site-nav-item-icon" target="_blank" rel="noopener noreferrer">
                                            <img 
                                                className="site-nav-icon-linkedin" 
                                                src="/images/icons/linkedin.png"
                                                alt="linkedin" 
                                            />
                                        </a>
                                    )}
                                    <a className="site-nav-item-icon" href={gmailUrl} target="_blank" rel="noopener noreferrer">
                                        <img 
                                            className="site-nav-icon-gmail" 
                                            src="/images/icons/gmail.png"
                                            alt="Gmail Icon" 
                                        />
                                    </a>
                                </div>
                            </div>
                            {isHome ? (
                                <div className="site-banner">
                                    <h1 className="site-banner-title">{site.meta_title}</h1>
                                    <p className="site-banner-desc">{site.description}</p>
                                </div>
                            ) : null}
                            <nav className="site-nav">
                                <div className="site-nav-left">
                                    {/* The navigation items as setup in settings.json */}
                                    <Navigation data={site.navigation} navClass="site-nav-item" />
                                </div>
                                <div className="site-nav-right">
                                    {/* <Link className="site-nav-button" to="/about">
                                        About
                                    </Link> */}
                                </div>
                            </nav>
                        </div>
                    </header>

                    <main className="site-main">
                        {/* All the main content gets inserted here, index.js, post.js */}
                        {children}
                    </main>
                </div>

                <div className="viewport-bottom">
                    {/* The footer at the very bottom of the screen */}
                    <footer className="site-foot">
                        <div className="site-foot-nav container">
                            <div className="site-foot-nav-left">
                                <Link to="/">{site.title}</Link> © 2025 &mdash;
                                Published with{" "}
                                <a className="site-foot-nav-item" href="https://ghost.org" target="_blank" rel="noopener noreferrer">
                                    Chongzhe Huang
                                </a>
                            </div>
                            <div className="site-foot-nav-right">
                                <Navigation data={site.navigation} navClass="site-foot-nav-item" />
                            </div>
                        </div>
                    </footer>
                </div>
            </div>
        </>
    );
};

DefaultLayout.propTypes = {
    children: PropTypes.node.isRequired,
    bodyClass: PropTypes.string,
    isHome: PropTypes.bool,
};

export default DefaultLayout;
